using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

var root = Globals.ThisService.RootDirectory;
var backupRoot = Path.Combine(root, "__tca_cfg_backup");
if (Directory.Exists(backupRoot)) Directory.Delete(backupRoot, true);
Directory.CreateDirectory(backupRoot);

var configFiles = Globals.ThisGame.ConfigFiles;
Globals.ScriptConsole.WriteLine("Config backup: " + (configFiles == null ? 0 : configFiles.Count) + " config file(s) defined for this game.");
int n = 0;
if (configFiles != null)
{
    foreach (var cf in configFiles)
    {
        if (string.IsNullOrWhiteSpace(cf.RelativePath)) continue;
        var rel = cf.RelativePath.Replace('\\', Path.DirectorySeparatorChar).Replace('/', Path.DirectorySeparatorChar).TrimStart(Path.DirectorySeparatorChar);
        var src = Path.Combine(root, rel);
        if (!File.Exists(src)) { Globals.ScriptConsole.WriteLine("  skip (not on disk): " + rel); continue; }
        var dst = Path.Combine(backupRoot, rel);
        Directory.CreateDirectory(Path.GetDirectoryName(dst));
        File.Copy(src, dst, true);
        n++;
        Globals.ScriptConsole.WriteLine("  backed up: " + rel);
    }
}
Globals.ScriptConsole.WriteLine("Config backup complete: " + n + " file(s).");

using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

var root = Globals.ThisService.RootDirectory;
var backupRoot = Path.Combine(root, "__tca_cfg_backup");
if (!Directory.Exists(backupRoot))
{
    Globals.ScriptConsole.WriteLine("Config restore: no backup found, nothing to restore.");
}
else
{
    var configFiles = Globals.ThisGame.ConfigFiles;
    int n = 0;
    if (configFiles != null)
    {
        foreach (var cf in configFiles)
        {
            if (string.IsNullOrWhiteSpace(cf.RelativePath)) continue;
            var rel = cf.RelativePath.Replace('\\', Path.DirectorySeparatorChar).Replace('/', Path.DirectorySeparatorChar).TrimStart(Path.DirectorySeparatorChar);
            var bak = Path.Combine(backupRoot, rel);
            if (!File.Exists(bak)) continue;
            var dst = Path.Combine(root, rel);
            Directory.CreateDirectory(Path.GetDirectoryName(dst));
            File.Copy(bak, dst, true);
            try { Globals.OperatingSystem.SetFileOwnerAutoDetect(dst); } catch { }
            n++;
            Globals.ScriptConsole.WriteLine("  restored: " + rel);
        }
    }
    try { Directory.Delete(backupRoot, true); } catch { }
    Globals.ScriptConsole.WriteLine("Config restore complete: " + n + " file(s) restored.");
}
